MOD = 10 ** 9 + 7
class Solution:
    def numberOfWays(self, n, x, y):
        dp = [0] * (x + 1)
        dp[0] = 1
        for i in range(1, n + 1):
            ndp = [0] * (x + 1)
            for s in range(x + 1):
                if dp[s] == 0:
                    continue
                ndp[s] = (ndp[s] + dp[s] * s) % MOD
                if s + 1 <= x:
                    ndp[s + 1] = (ndp[s + 1] + dp[s] * (x - s)) % MOD
            dp = ndp
        total = 0
        for s in range(1, x + 1):
            total = (total + dp[s] * pow(y, s, MOD)) % MOD
        return total % MOD

