MOD = 10 ** 9 + 7
class Solution:
    def numberOfWays(self, n, x, y):
        maxk = min(n, x)
        N = max(n, x) + 2
        fact = [1] * N
        for i in range(1, N):
            fact[i] = fact[i - 1] * i % MOD
        inv_fact = [1] * N
        inv_fact[N - 1] = pow(fact[N - 1], MOD - 2, MOD)
        for i in range(N - 2, -1, -1):
            inv_fact[i] = inv_fact[i + 1] * (i + 1) % MOD
        def C(a, b):
            if b < 0 or b > a:
                return 0
            return fact[a] * inv_fact[b] % MOD * inv_fact[a - b] % MOD
        total = 0
        for k in range(1, maxk + 1):
            s = 0
            for i in range(k + 1):
                term = C(k, i) * pow(k - i, n, MOD) % MOD
                if i % 2 == 0:
                    s = (s + term) % MOD
                else:
                    s = (s - term) % MOD
            s %= MOD
            contrib = C(x, k) * s % MOD * pow(y, k, MOD) % MOD
            total = (total + contrib) % MOD
        return total % MOD

