var numberOfWays = function(n, x, y) {
    const MOD = 1000000007n;
    const maxk = Math.min(n, x);
    const N = Math.max(n, x) + 2;
    const fact = new Array(N).fill(1n);
    for (let i = 1; i < N; i++) fact[i] = fact[i - 1] * BigInt(i) % MOD;
    function power(a, b, m) {
        a %= m; if (a < 0n) a += m;
        let res = 1n;
        while (b > 0n) {
            if (b & 1n) res = res * a % m;
            a = a * a % m;
            b >>= 1n;
        }
        return res;
    }
    const invFact = new Array(N).fill(1n);
    invFact[N - 1] = power(fact[N - 1], MOD - 2n, MOD);
    for (let i = N - 2; i >= 0; i--) invFact[i] = invFact[i + 1] * BigInt(i + 1) % MOD;
    function C(a, b) {
        if (b < 0 || b > a) return 0n;
        return fact[a] * invFact[b] % MOD * invFact[a - b] % MOD;
    }
    let total = 0n;
    for (let k = 1; k <= maxk; k++) {
        let s = 0n;
        for (let i = 0; i <= k; i++) {
            const term = C(k, i) * power(BigInt(k - i), BigInt(n), MOD) % MOD;
            if (i % 2 === 0) s = (s + term) % MOD;
            else s = (s - term + MOD) % MOD;
        }
        s = ((s % MOD) + MOD) % MOD;
        const contrib = C(x, k) * s % MOD * power(BigInt(y), BigInt(k), MOD) % MOD;
        total = (total + contrib) % MOD;
    }
    return Number(((total % MOD) + MOD) % MOD);
};
